mapper.select:
/* FAQ 목록 조회 */ select a.faq_idx, a.question, a.answer, b.faq_cate_idx, b.faq_cate_name from tb_faq a, tb_faq_category b where a.faq_cate_idx = b.faq_cate_idx and a.del_yn = 'N'
and a.faq_cate_idx = #{cateIdx}
and (a.question like concat('%', #{search}, '%') or a.answer like concat('%', #{search}, '%'))
order by a.reg_date desc

/* FAQ 목록 조회 */
select
count(*) as listCnt
from(
select
a.faq_idx, a.question, a.answer, b.faq_cate_idx, b.faq_cate_name
from tb_faq a, tb_faq_category b
where a.faq_cate_idx = b.faq_cate_idx
and a.del_yn = 'N'

    and a.faq_cate_idx = #{cateIdx}


    and (a.question like concat('%', #{search}, '%') or a.answer like concat('%', #{search}, '%'))

) f_tb

/* FAQ 카테고리 한건 조회 */
select
	faq_cate_idx, faq_cate_name
from tb_faq_category
where faq_cate_idx = #{faqCateIdx}

/* FAQ 한건 조회 */
select
	faq_idx, faq_cate_idx, question, replace(answer, '<br/>', '\\n') answer
from tb_faq
where del_yn = 'N'
and faq_idx = #{faqIdx}

mapper.insert:
/* FAQ 카테고리 등록 */ insert into tb_faq_category (
faq_cate_name, /* 카테고리명 */ reg_uid, /* 등록자ID */ reg_date /* 등록일시 */ ) values (
#{faqCateName }, #{regUid }, now() )

/* FAQ 등록 */ insert into tb_faq (
faq_cate_idx, /* 카테고리식별자 */ question, /* 질문 */ answer, /* 답변 */ del_yn, /* 삭제여부(Y:예,N:아니오) */ reg_uid, /* 등록자ID */ reg_date /* 등록일시 */ ) values (
#{faqCateIdx }, #{question }, #{answer }, 'N', #{regUid }, now() )

mapper.delete:
/* FAQ 카테고리 삭제 */
delete from tb_faq_category
where faq_cate_idx = #{faqCateIdx }

mapper.update:
/* FAQ 삭제 */
delete from  tb_faq
where faq_idx = #{faqIdx }

mapper.select:
/* 자료실 목록 조회 */ select t1.*, t2.rfnc_cate_name from tb_reference t1, tb_reference_category t2 where t1.rfnc_cate_idx = t2.rfnc_cate_idx
and t1.rfnc_cate_idx = #{cateIdx}
and (t1.title like concat('%', #{search}, '%') or t1.contents like concat('%', #{search}, '%'))
order by t1.reg_date desc

        /* 자료실 목록 조회 */
		select * from tb_attach_file
		where attach_idx = #{attach_idx}

/* FAQ 목록 조회 */
select
count(*) as listCnt
from(
select
a.rfnc_idx, a.title, a.contents, b.rfnc_cate_idx, b.rfnc_cate_name
from tb_reference a, tb_reference_category b
where a.rfnc_cate_idx = b.rfnc_cate_idx

    and a.rfnc_cate_idx = #{cateIdx}


    and (a.title like concat('%', #{search}, '%') or a.contents like concat('%', #{search}, '%'))

) f_tb

mapper.delete:
/* 자료 삭제 */
delete from  tb_reference
where rfnc_idx = #{referIdx}

/* 자료 삭제 */
delete from tb_attach_file
where attach_idx = (
				select attach_idx 
				from tb_reference 
				where rfnc_idx = #{referIdx}
				)

/* 자료실 카테고리 삭제 */
delete from tb_reference_category
where rfnc_cate_idx = #{cateIdx }

mapper.select:
/* 자료실 카테고리 한건 조회 */
select
	rfnc_cate_idx, rfnc_cate_name
from tb_reference_category
where rfnc_cate_idx = #{referCateIdx}

/* 자료 한건 조회 */
select *
from tb_attach_file
where attach_idx = #{attachIdx}

		select IFNULL(max(attach_idx_no) +1, 1) as attach_idx_no,
	 		   IFNULL(sum(file_size), 0) as tot_size
      	from tb_attach_file where attach_idx = #{attachIdx};

mapper.delete:
/* 자료실 카테고리 삭제 */
delete from tb_attach_file
where attach_idx = #{attachIdx}
 and attach_idx_no = #{attachIdxNo}
